const currentMonth = new Date().getMonth() + 1;
const results = [];

for (const [asset, months] of Object.entries(seasonality)) {
  const current = months.find(m => m.month === currentMonth);
  if (!current) continue;

  let bias = 'neutral';
  if (current.avg_return > 1.5 && current.win_rate > 60) bias = 'bullish';
  else if (current.avg_return < -1.5 && current.win_rate < 40) bias = 'bearish';
  else if (current.avg_return > 0.5) bias = 'mildly_bull';
  else if (current.avg_return < -0.5) bias = 'mildly_bear';

  results.push({
    json: {
      asset,
      month: currentMonth,
      avg_return: current.avg_return,
      win_rate: current.win_rate,
      sample_years: current.sample_years,
      current_bias: bias
    }
  });
}

return results;

const items = $input.all();
const currentMonth = new Date().toLocaleString('en', { month: 'long' });

const strong = items.filter(i => i.json.current_bias === 'bullish' || i.json.current_bias === 'bearish');
if (!strong.length) return [{ json: { skip: true } }];

const lines = strong.map(i => {
  const j = i.json;
  const arrow = j.avg_return > 0 ? '\u25b2' : '\u25bc';
  const emoji = j.current_bias === 'bullish' ? '\ud83d\udfe2' : '\ud83d\udd34';
  return `${emoji} *${j.asset}*: ${arrow} ${j.avg_return > 0 ? '+' : ''}${j.avg_return}% avg (${j.win_rate}% win, ${j.sample_years}yr)`;
}).join('\n');

const msg = `\ud83d\udcc5 *Seasonal Signals — ${currentMonth}*\n\n${lines}\n\n_Strong historical patterns (>60% win rate)_`;
return [{ json: { message: msg, skip: false } }];

